import numpy as np

def euclidean_distance(point1, point2):
    return np.linalg.norm(point1 - point2)

def travel_time(point1, point2, speed):
    return euclidean_distance(point1, point2) / speed

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_penalty = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        time_window_start, time_window_end = time_windows[i]
        travel = travel_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel

        if arrival_time > time_window_end:
            continue  # Skip if the time window is already missed

        wait_time = max(0, time_window_start - arrival_time)
        penalty = travel + wait_time  # Base penalty is the travel time + wait time

        if arrival_time < time_window_start:
            penalty += time_window_start - arrival_time  # Additional penalty for arriving early

        if penalty < min_penalty:
            min_penalty = penalty
            best_node = i

    # If no customer was feasible, consider waiting at the current position
    if best_node is None:
        best_node = None  # Wait at current position

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    best_node = None
    min_penalty = float('inf')
    feasible_customer_indices = []

    for i, customer in enumerate(unvisited_customers):
        distance_to_customer = euclidean_distance(cur_truck_pos, customer)
        arrival_time = current_time + (distance_to_customer / truck_speed)

        if time_windows[i][0] <= arrival_time <= time_windows[i][1]:
            if time_windows[i][1] < min_penalty:
                min_penalty = time_windows[i][1]
                best_node = i
            feasible_customer_indices.append(i)
        elif arrival_time < time_windows[i][0] and time_windows[i][0] < min_penalty:
            best_node = i
            min_penalty = time_windows[i][0]

    if best_node is None:
        best_node = 'None'  # Wait or return to depot

    return best_node
